package main

import (
 "fmt"
 "net/http"
)

func handler(w http.ResponseWriter, _ *http.Request) { fmt.Fprintln(w, "{{PROJECT_NAME}} ready") }
func main() { http.HandleFunc("/", handler); _ = http.ListenAndServe("127.0.0.1:8080", nil) }

