package main

import (
 "net/http/httptest"
 "strings"
 "testing"
)
func TestHandler(t *testing.T) { w := httptest.NewRecorder(); handler(w, httptest.NewRequest("GET", "/", nil)); if !strings.Contains(w.Body.String(), "ready") { t.Fatal(w.Body.String()) } }

